import{_ as a,o as t,c,ai as o}from"./chunks/framework.CsYGeNYI.js";const n=JSON.parse('{"title":"WebChat","description":"","frontmatter":{"read_when":["调试或配置 WebChat 访问"],"summary":"用于聊天 UI 的 loopback WebChat 静态主机和 Gateway 网关 WS 使用","title":"WebChat","x-i18n":{"generated_at":"2026-02-03T10:13:28Z","model":"claude-opus-4-5","provider":"pi","source_hash":"b5ee2b462c8c979ac27f80dea0cf12cf62b3c799cf8fd0a7721901e26efeb1a0","source_path":"web/webchat.md","workflow":15}},"headers":[],"relativePath":"zh-CN/web/webchat.md","filePath":"zh-CN/web/webchat.md","lastUpdated":null}'),i={name:"zh-CN/web/webchat.md"};function d(l,e,h,r,s,b){return t(),c("div",null,[...e[0]||(e[0]=[o('<h1 id="webchat-gateway-网关-websocket-ui" tabindex="-1"><a class="header-anchor" href="#webchat-gateway-网关-websocket-ui">#</a> WebChat（Gateway 网关 WebSocket UI）</h1><p>状态：macOS/iOS SwiftUI 聊天 UI 直接与 Gateway 网关 WebSocket 通信。</p><h2 id="它是什么" tabindex="-1"><a class="header-anchor" href="#它是什么">#</a> 它是什么</h2><ul><li>Gateway 网关的原生聊天 UI（无嵌入式浏览器，无本地静态服务器）。</li><li>使用与其他渠道相同的会话和路由规则。</li><li>确定性路由：回复始终返回到 WebChat。</li></ul><h2 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始">#</a> 快速开始</h2><ol><li>启动 Gateway 网关。</li><li>打开 WebChat UI（macOS/iOS 应用）或控制 UI 聊天标签页。</li><li>确保已配置 Gateway 网关认证（默认需要，即使在 loopback 上）。</li></ol><h2 id="工作原理-行为" tabindex="-1"><a class="header-anchor" href="#工作原理-行为">#</a> 工作原理（行为）</h2><ul><li>UI 连接到 Gateway 网关 WebSocket 并使用 <code>chat.history</code>、<code>chat.send</code> 和 <code>chat.inject</code>。</li><li><code>chat.inject</code> 直接将助手注释追加到转录并广播到 UI（无智能体运行）。</li><li>历史记录始终从 Gateway 网关获取（无本地文件监听）。</li><li>如果 Gateway 网关不可达，WebChat 为只读模式。</li></ul><h2 id="远程使用" tabindex="-1"><a class="header-anchor" href="#远程使用">#</a> 远程使用</h2><ul><li>远程模式通过 SSH/Tailscale 隧道传输 Gateway 网关 WebSocket。</li><li>你不需要运行单独的 WebChat 服务器。</li></ul><h2 id="配置参考-webchat" tabindex="-1"><a class="header-anchor" href="#配置参考-webchat">#</a> 配置参考（WebChat）</h2><p>完整配置：<a href="/docs/gateway/configuration">配置</a></p><p>渠道选项：</p><ul><li>没有专用的 <code>webchat.*</code> 块。WebChat 使用下面的 Gateway 网关端点 + 认证设置。</li></ul><p>相关的全局选项：</p><ul><li><code>gateway.port</code>、<code>gateway.bind</code>：WebSocket 主机/端口。</li><li><code>gateway.auth.mode</code>、<code>gateway.auth.token</code>、<code>gateway.auth.password</code>：WebSocket 认证。</li><li><code>gateway.remote.url</code>、<code>gateway.remote.token</code>、<code>gateway.remote.password</code>：远程 Gateway 网关目标。</li><li><code>session.*</code>：会话存储和主键默认值。</li></ul>',16)])])}const p=a(i,[["render",d]]);export{n as __pageData,p as default};
